var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"역신 오로치를 막기 위해 많은 희생이 있었다.","JPN":"疫病神オロチを止めるため多くの犠牲があった。","ENG":"There were many sacrifices in order to stop Orochi, the Plague God.","TWN":"因為要阻止瘟神大蛇而造成許多犧牲。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"긴 싸움 끝에 명부신이 오로치의 목을 베었지만, 이미 세상은 역신의 독으로 무너지고 있었다.","JPN":"長い戦いの末に冥府の神がオロチの首を打ったが、すでに世界は疫病神の毒で崩れかけていた。","ENG":"After what seemed like an endless battle, the Nether God finally succeeded in slaying Orochi’s head. But the world was already destroyed by the Plague God’s poison.","TWN":"經過漫長的抗爭，冥府神最終斬下大蛇的頭，世界卻已經因為瘟神的毒而崩塌。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"명부신은 자신의 세 자손을 한 자리에 불러모아, 세 가지 재앙을 예견하고 이에 대비하도록 했다.","JPN":"冥府の神は三人の子孫を呼び寄せ、三つの災いを予言してそれに備えさせた。","ENG":"So the Nether God brought together his three descendants and predicted three catastrophes, to make them prepare for the inevitable.","TWN":"冥府神於是召聚三個兒子，並預言會有三個災難，要他們為此做好準備。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"세 자손은 그 유언을 받들어 명부신의 영혼으로 옥을 빗고, 역신의 비늘로 검을 만들었다.","JPN":"三人の子孫はその遺言に従い冥府の神の魂で宝玉を作り、疫病神の鱗で剣を作った。","ENG":"The three descendants took his will, shaping his soul into a sacred jade, while also using his scales to make a sword.","TWN":"三個兒子聽完冥府神的遺言後，將其靈魂凝聚成玉石，並且用瘟神的鱗片打造出一把寶劍。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그중 하나가 지금의 나나하라 영지에 숨겨진 결계옥.","JPN":"そのうちの一つが現在七原領地内に隠されておる結界玉。","ENG":"The jade is Akaitama hidden in the Nanahara estate.","TWN":"其中一個就是目前藏在七原領地裡的結界玉石。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"다른 하나는 나나하라 가문 대대로 물려져 내려오는 천총운검이지.","JPN":"もう一つは七原家に代々伝わる天叢雲剣じゃ。","ENG":"The other is the Sword of Kusanagi, passed down for generation within the Nanahara family.","TWN":"另一個就是七原家族代代相傳的天叢雲劍。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"첫째는 봉인역의 결계를 지키기 위해. 둘째는 오로치를 막기 위한 것이죠.","JPN":"一つ目は封印域の結界を守るための。二つ目はオロチを阻止するためのものですね。","ENG":"The former is to protect the Seal Domain, and the latter is to stop Orochi.","TWN":"玉石的功用是保護封印域的結界，寶劍的用途則是抵抗大蛇。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 세번째 신기인 역신베기는 그 생김새와 쓰임새에 대해 들어본 적도 없습니다.","JPN":"ですが三つ目の神器である大蛇薙剣はその形や使い道について聞いたことがございません。","ENG":"But never have I heard of the usage and appearance of Orochinagi.","TWN":"不過第三個神器瘟神斬，我卻從未聽說過它的樣子和用途。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그야 아직 완성되지 못했으니 그러지.","JPN":"そりゃあまだ完成していないからのう。","ENG":"That’s because it’s not completed yet.","TWN":"那是因為還沒完成的關係。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 그렇다면…… 세번째로 예견된 재앙을 막는 법이 없는 건가요?","JPN":"はい？　でしたら……予言された三度目の災いを止める方法はないのですか？","ENG":"What? Then... is there no way to stop the third catastrophe from happening?","TWN":"什麼？所以意思是……目前沒有方法可以阻止預言的第三個災難嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 선조는 오랫동안 역신베기의 마지막 재료를 찾기 위해 노력했다.","JPN":"わしの先祖は長らく大蛇薙剣の最後の材料を探すために頑張ってきたのだが。","ENG":"For years, my ancestors have searched for the last component in finishing Orochinagi.","TWN":"我的祖先一直在努力尋找瘟神斬最後的材料。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 끝내 찾아내지 못했고, 내가 그 유지를 잇고자 이곳에 온 게다.","JPN":"結局見つからず、今回わしがその遺志を受け継いでここへ来たというわけじゃ。","ENG":"But they never did. Thus here I am to success their will.","TWN":"但始終沒能找到，而我則是繼承祖先的遺願才會來到這裡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 말씀해주세요.","JPN":"それなら、どうぞおしゃってください。","ENG":"Please tell me.","TWN":"那請告訴我，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희가 어떤 도움을 드리면 되겠습니까?","JPN":"私たちがどのようにお手伝いしたらいいのですか？","ENG":"How can we help you?","TWN":"我們該如何幫您呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신베기는 두려워 할 죽음이 없는 무사가 자신의 목숨을 바쳐 완성되리라.","JPN":"大蛇薙剣は恐れるべき死のない武士が自らの命を捧げることにより完成するであろう。","ENG":"Completed shall Orochinagi be, with the life of a warrior unafraid of all death.","TWN":"瘟神斬必須由無懼死亡的武士獻上自己的性命才能完成。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그것이 명부신께서 예견한 역신베기의 조건이지.","JPN":"それが冥府の神が予言なさった大蛇薙剣の条件じゃ。","ENG":"That is the prerequisite of completing Orochinagi.","TWN":"這是完成瘟神斬的條件。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"목숨이라 함은…… 설마 희생을 의미하는 것인가요?","JPN":"命と申しますと……まさか犠牲を意味しているのですか？","ENG":"\\"With the life\\"... Do you mean sacrifices?","TWN":"性命……該不會是要犧牲性命吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어린 것이 이해가 빨라서 좋구나.","JPN":"物わかりの良い子じゃのう。","ENG":"You’re quite bright for your young age.","TWN":"你的反應很快呢，很好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송하지만, 그렇게 할 수 없습니다.","JPN":"申し訳ありませんが、それはできません。","ENG":"I’m sorry, but that won’t be possible.","TWN":"抱歉，那恕我們幫不上忙。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何じゃと？","ENG":"...What did you just say?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"신기의 완성을 위해 희생을 강요하지 않더라도, 분명 다른 방법이 있을 것입니다.","JPN":"神器を完成するために犠牲を強要しなくとも、きっと他に方法があるはずです。","ENG":"There will be other ways than making sacrifices for completing the Sacred Treasure.","TWN":"我相信不是非要犧牲性命才能完成神器，一定有其他辦法的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 부디 말씀을 거두어 주십시오.","JPN":"ですので、どうかご容赦ください。","ENG":"So please, I beg you to take back your request.","TWN":"請您把話收回去。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"신기를 완성하는 것은 명부신의 마지막 전언이요. 내 선조의 오랜 뜻이다.","JPN":"神器を完成させることは冥府の神の遺言であり、わしの先祖の悲願だ。","ENG":"Completing the Sacred Treasures is the will of the Nether God and my ancestors.","TWN":"完成神器是冥府神最後的遺言，也是我的祖先一直以來的志願。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"고작 어린 당주 하나가 반대한다고 될 일이 아니야.","JPN":"チビ当主一人が反対したからといってどうにかなるものではない。","ENG":"It’s not something that can be stopped with refusal of a young Nanahara.","TWN":"不會因為區區一個年輕堂主反對就停止。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님. 하바키를 이송하는 차량이 움직이기 시작했습니다.","JPN":"ご当主様。覇吐を移送する車両が動き始めました。","ENG":"My lady. Habaki is now being transported.","TWN":"堂主，要準備移送幅木了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 저도 당장 그리로 갈게요.","JPN":"はい、私もすぐそちらに向かいます。","ENG":"I see. I will be there soon.","TWN":"好，我立刻過去。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송합니다, 나오님.","JPN":"申し訳ございません、ナオ様。","ENG":"Please excuse me, Miss Nao.","TWN":"奈緒大人，很抱歉，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희에겐 아직 마무리 지어야 할 일들이 남아있어요.","JPN":"私たちにはまだケリをつけるべき事が残っております。","ENG":"We still have a lot to take care of.","TWN":"我們還有一些事要去處理。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유도, 사나에도…… 그런 식으로 희생되는 것은 바라지 않습니다.","JPN":"千冬にも、早苗にも……そのように犠牲になることは望みません。","ENG":"I do not want anyone to be sacrificed like that... including Chifuyu and Sanae.","TWN":"無論是千冬或早苗……我都不希望他們以那種形式犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"시간을 끌어봐야 좋을 거 없다.","JPN":"長引かせてもいいことなどないぞ。","ENG":"There is no good in denying it.","TWN":"再拖下去沒好處。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아무런 희생도 치르지 않는다는 건…… 허울좋은 소리일 뿐이야.","JPN":"なんの犠牲も払わないというのは……体のいい言葉に過ぎん。","ENG":"To assume there shall not be any bloodshed... is a foolish assumption.","TWN":"不願意有任何犧牲……只是句好聽話而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……걱정 마십시오.","JPN":"……ご心配はいりません。","ENG":"...Do not worry.","TWN":"……請放心，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"만일 누군가의 영혼을 바쳐야만 하는 때가 온다면……","JPN":"仮に誰かの魂を捧げなくてはいけない時が来たとしたら……","ENG":"If someone has to sacrifice their own life...","TWN":"萬一真的有必須獻上誰的靈魂的時候……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그땐 제가 반드시 대가를 치르겠습니다.","JPN":"その時には私が必ず代償を払います。","ENG":"Then I will be the one to do so.","TWN":"到時候我願意付出代價。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"이봐. 왜 갑자기 선두차량이 멈춘 거야?","JPN":"おい。なんでいきなり先頭車両が止まったんだ？","ENG":"Hey. Why did the lead vehicle stop all of a sudden?","TWN":"喂，前導車為何突然停下來？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"바리케이드다. 길이 막혀 있어.","JPN":"バリケードだ。道が塞がれてる。","ENG":"There’s a barricade. The road is blocked.","TWN":"有拒馬擋住去路。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 이동 경로는 공유가 됐을 텐데? 누가 저런 걸 쳐 놓은 거지?","JPN":"俺たちの移動経路は知らせてあるはずだぞ？　誰があんなものを置いたんだ？","ENG":"I thought our route was already passed on. Who would have possibly done such a thing?","TWN":"我們的行進路線不是有同步給大家嗎？是誰擺放拒馬的？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"뭐야 저 인간들? 침식사태가 한창인데 대피도 안 하고……","JPN":"なんだ、あいつら？　侵食事態の真っ最中なのに退避もせずに……","ENG":"Who are those people? They’re not evacuating from the Corruption disaster...","TWN":"那些人怎麼回事？侵蝕事件這麼嚴重，還不快去躲起來……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"무장한 걸로 봐선 태스크포스인가?","JPN":"武装してるところを見るとタスクフォースか？","ENG":"Judging from their looks, they look like TASKFORCE.","TWN":"看他們那身裝備應該是特遣勢力？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"이봐! 거기! 빨리 길 열어! 이쪽은 관리국 호송차량이다!","JPN":"おい！　そこ！　早く道を開けろ！　こっちは管理局の護送車両だ！","ENG":"Hey, you! Clear the road! We’re from the Administration!","TWN":"喂！你們快讓開！我們是管理局的護送車隊！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"저런 어줍잖은 병사들에게 일을 맡기다니. 관리국도 꽤나 허술해졌군.","JPN":"あのようなくだらない兵士に仕事を任すとは。管理局も緩くなったものだ。","ENG":"Hiring such phonies to get the job done... The Administration is losing its legacy.","TWN":"竟然把這麼重要的事交給那種二百五，管理局做事蠻混的嘛。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"레노어, 위치는?","JPN":"レノア、位置は？","ENG":"Lenore, where is he?","TWN":"蕾諾雅，位置？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_QM","text":{"KOREA":"<color=#ffd34c>세번째 차량 컨테이너에 있어요, 아버지.</color>","JPN":"<color=#ffd34c>三番目の車両のコンテナにいます、お父様。</color>","ENG":"<color=#ffd34c>He’s in the container of the third vehicle, father.</color>","TWN":"<color=#ffd34c>在第三台貨櫃車裡，父親。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"탈환한다.","JPN":"奪還する。","ENG":"Retrieve him.","TWN":"奪回來！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"저, 저것들 갑자기 뭐하는 거야?","JPN":"あ、あいつら、いきなり何するんだ？","ENG":"W-what are they doing?!","TWN":"他…他們想做什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"이런! 공격받는다!","JPN":"まずい！　攻撃されるぞ！","ENG":"Damn it! We’re under attack!","TWN":"糟糕！受到攻擊！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L21_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"초, 총알이 떨어졌어?","JPN":"じゅ、銃弾が切れた！？","ENG":"I-I ran out of ammo...","TWN":"子…子彈沒用？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"으아악! 오…… 오지마!","JPN":"うわあっ！　く……来るな！","ENG":"Aaaaah! S-stay back!","TWN":"呃啊啊！……別過來！"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"사람……?","JPN":"人間……？","ENG":"A person...?","TWN":"你是人……？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"뒤쪽에 확보된 대피로가 있습니다! 가십시오!","JPN":"後ろに退避路を確保してあります！　行ってください！","ENG":"There’s a secured exit at the back! Go!","TWN":"後面有安全的避難所！走吧！"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"예, 예엣!","JPN":"は、はっ！","ENG":"Y-yes ma’am!","TWN":"喔，好！"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"오너라.","JPN":"来い。","ENG":"Come here.","TWN":"快來！"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이런, 검이 무거워 휘두를 수가……!","JPN":"ダメだ、刀が重くて振り回せない……！","ENG":"Tsk, the sword is too heavy to–!","TWN":"糟糕，劍太沉揮不……！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치후유! 괜찮아?","JPN":"千冬！　大丈夫？","ENG":"Chifuyu! Are you okay?","TWN":"千冬！你沒事吧？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공…… 전 괜찮습니다.","JPN":"奈由香殿……私は大丈夫です。","ENG":"Mr. Nayuka... I am fine, thank you.","TWN":"南裕夏……我沒事。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"혹시 팔을 다친 거야? 검을 휘두르는 게 불편해 보이던데.","JPN":"もしかして腕を怪我でもした？　刀を振りにくそうに見えたけど。","ENG":"Did you hurt your arm? You don't look comfortable swinging your sword.","TWN":"你的手臂受傷了嗎？我看你揮劍時好像有點吃力？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"베는 것은 어렵지만…… 공격을 막는 것은 문제없습니다.","JPN":"斬れはしませんが……攻撃を止めるのには問題ありません。","ENG":"I cannot attack... but I can block for now.","TWN":"要斬殺會有點困難……但抵擋攻擊是沒問題的。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다 같이 밥 먹는 건 다음으로 미뤄야겠네.","JPN":"みんなで食事をするのはまた今度になりそうだね。","ENG":"I guess we’re going to have to delay our meal together to next time.","TWN":"只能等下次再一起吃飯了。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"도움 좀 빌릴게.","JPN":"ちょっと手伝ってもらうよ。","ENG":"Would you mind lending me a hand?","TWN":"我幫你。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럼 뒤를 부탁드립니다.","JPN":"それでは、後ろをお願いいたします。","ENG":"Take the back, please.","TWN":"那後面就麻煩你了。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};